import net.devh.boot.grpc.client.inject.GrpcClient;


@Service
public class PresenceHandlerImpl implements PresenceHandler {

    private final ObjectMapper objectMapper;
    private final MeasurementsProperties measurementsProperties;
    @GrpcClient("default-channel")
    private final YandexServiceGrpc.YandexServiceStub yandexServiceStub;

    public PresenceHandlerImpl(ObjectMapper objectMapper, YandexServiceGrpc.YandexServiceStub yandexServiceStub, MeasurementsProperties measurementsProperties) {
        this.objectMapper = objectMapper;
        this.yandexServiceStub = yandexServiceStub;
        this.measurementsProperties = measurementsProperties;
    }

    @Override
    public Mono<EventDTO> handleIncomingData(String jsonData) {
        return Mono.fromCallable(() -> {
                    validateJsonFormat(jsonData);
                    return jsonData;
                })
                .flatMap(data -> {
                    EventDTO eventDTO = JsonDtoParser.parseJson(jsonData);
                    return eventDTO.measurements().stream()
                            .filter(m -> m.type().equals(measurementsProperties.getLampState().getName()))
                            .findFirst()
                            .map(m -> {
                                Yandex.TurnOnOffLampRequest request = Yandex.TurnOnOffLampRequest.newBuilder()
                                        .setTurnOn((Boolean) m.value())
                                        .build();

                                // gRPC вызов асинхронно в реактивном потоке
                                return Mono.fromCallable(() -> yandexServiceStub.turnOnOffLamp(request))
                                        .thenReturn(eventDTO); // возвращаем EventDTO дальше
                            })
                            .orElse(Mono.just(eventDTO));
                });

    }

    private void validateJsonFormat(String jsonData) {
        try {
            JsonNode root = objectMapper.readTree(jsonData);
            JsonNode measurements = root.path("measurements");

            if (!measurements.has(measurementsProperties.getRadarPresence().getName())
                || !measurements.has(measurementsProperties.getPirSensorPresence().getName())
                || !measurements.has(measurementsProperties.getLampState().getName())) {
                throw new IllegalArgumentException("NodeMCU requires radarPresence, pirSensorPresence and lampState measurements");
            }
        } catch (JsonProcessingException e) {
            throw new IllegalArgumentException("Invalid JSON format", e);
        }
    }
}

package dev.iot.presenceservice.service;

import com.fasterxml.jackson.databind.ObjectMapper;
import dev.iot.shared.dto.MeasurementDTO;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import reactor.test.StepVerifier;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.AssertionsForClassTypes.tuple;

class PresenceHandlerImplTest {

    private PresenceHandlerImpl presenceHandler;

    @BeforeEach
    void setUp() {
        presenceHandler = new PresenceHandlerImpl(new ObjectMapper());
    }

    @Test
    @DisplayName("Should handle presence sensor data")
    void shouldHandlePresenceData() {
        String jsonData = """
                {
                    "sensorId": "NodeMCU",
                    "measurements": {
                        "radarPresence": true,
                        "pirSensorPresence": false,
                        "lampState": true
                    }
                }
                """;

        StepVerifier.create(presenceHandler.handleIncomingData(jsonData))
                .assertNext(eventDTO -> {
                    assertThat(eventDTO.measurements()).hasSize(3);

                    assertThat(eventDTO.measurements())
                            .extracting(MeasurementDTO::type, MeasurementDTO::value)
                            .containsExactlyInAnyOrder(
                                    tuple("radarPresence", true),
                                    tuple("pirSensorPresence", false),
                                    tuple("lampState", true)
                            );
                })
                .verifyComplete();
    }

    @Test
    @DisplayName("Should reject data without required fields")
    void shouldRejectDataWithoutRequiredFields() {
        String invalidJsonData = "{}";

        StepVerifier.create(presenceHandler.handleIncomingData(invalidJsonData))
                .expectError(IllegalArgumentException.class)
                .verify();
    }

    @Test
    @DisplayName("Should handle complex sensor data")
    void shouldHandleComplexSensorData() {
        String jsonData = """
                {
                    "sensorId": "NodeMCU",
                    "measurements": {
                        "radarPresence": true,
                        "pirSensorPresence": false,
                        "lampState": true
                    }
                }
                """;

        StepVerifier.create(presenceHandler.handleIncomingData(jsonData))
                .assertNext(eventDTO -> {
                    assertThat(eventDTO.measurements()).hasSize(3);

                    assertThat(eventDTO.measurements())
                            .extracting(MeasurementDTO::type)
                            .containsExactlyInAnyOrder("radarPresence", "pirSensorPresence", "lampState");
                })
                .verifyComplete();
    }
}

